import { HealthService } from '../../services/health.service.js';
import { FilesService } from '../../services/files.service.js';
import { navigate } from '../../router.js';
import { refreshIfStale } from '../../services/sync/snapshot-refresh.service.js';
import { buildSectionPage } from '../../utils/section-page.utils.js';
import { createComponentLogger } from '../../utils/component-logger.js';
import { safeExec } from '../../utils/safe-exec.js';
import { documentStyleSheet } from '../../utils/css.js';
import stylesText from './health-estimate-review-screen.css?inline';
import type { ScreenComponent } from '../../types/screen-component.js';
import { GPU_CONTENDED_REASON, type EstimateJob, type EstimateJobResult, type FoodItem, type ResolutionProvenance } from '@motivation/shared';

documentStyleSheet(stylesText);

/**
 * Story 211 — the async-estimate review screen. The notification deep-links
 * here (data.path = /health/estimates/:id), and the submit flow navigates here
 * after enqueueing — so it must handle every job state:
 *   - queued  → spinner + poll (the user can leave; the push brings them back)
 *   - done    → the assembled result + Log / Edit / Archive
 *   - failed  → the raw error + Retry / Archive (fail loud)
 * Nothing is persisted until the user acts: Log materializes+logs the meal/food,
 * Edit materializes the meal and opens the editor, Archive discards.
 */

const PROVENANCE_LABELS: Record<ResolutionProvenance, string> = {
    matched_library: 'library',
    matched_off: 'Open Food Facts',
    generated: 'AI estimate',
};

const PROVENANCE_CLASS: Record<ResolutionProvenance, string> = {
    matched_library: 'provenance-library',
    matched_off: 'provenance-off',
    generated: 'provenance-generated',
};

const POLL_MS = 2500;

function kcalOf(item: FoodItem, amount: number): number {
    return item.calories_per_base != null && item.base_amount > 0 ? (item.calories_per_base * amount) / item.base_amount : 0;
}

function resultKcal(result: EstimateJobResult): number {
    if (result.kind === 'food_item') return kcalOf(result.food_item, result.resolution.amount);
    return result.ingredients.reduce((sum, ing) => sum + kcalOf(ing.food_item, ing.amount), 0);
}

export class HealthEstimateReviewScreen extends HTMLElement implements ScreenComponent {
    private jobIdValue: string | null = null;
    private content: HTMLElement | null = null;
    private pollTimer: number | null = null;
    private initialized = false;
    private readonly log = createComponentLogger('health-estimate-review-screen');

    setLoading(): void {}
    setError(err: unknown): void {}
    clearStatus(): void {}

    set jobId(value: string | null) {
        this.jobIdValue = value;
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;
        const page = buildSectionPage(this, 'Meal estimate', 'health', '/health');
        this.content = page.content;
        void this.load();
    }

    disconnectedCallback(): void {
        this.stopPolling();
    }

    private stopPolling(): void {
        if (this.pollTimer !== null) {
            clearTimeout(this.pollTimer);
            this.pollTimer = null;
        }
    }

    private async load(): Promise<void> {
        if (!this.jobIdValue) {
            this.renderMessage('No estimate selected.');
            return;
        }
        try {
            const job = await HealthService.getEstimateJob(this.jobIdValue);
            this.renderJob(job);
            this.stopPolling();
            if (job.status === 'queued') {
                this.pollTimer = window.setTimeout(() => void this.load(), POLL_MS);
            }
        } catch (err) {
            this.renderMessage(err instanceof Error ? err.message : 'Failed to load the estimate.');
        }
    }

    private reset(): HTMLElement {
        const root = this.content!;
        root.replaceChildren();
        const section = document.createElement('div');
        section.className = 'estimate-review';
        root.appendChild(section);
        return section;
    }

    private renderMessage(message: string): void {
        const section = this.reset();
        const p = document.createElement('p');
        p.className = 'screen-error';
        p.textContent = message;
        section.appendChild(p);
    }

    private renderJob(job: EstimateJob): void {
        if (job.status === 'queued') return this.renderQueued();
        if (job.status === 'failed') return this.renderFailed(job);
        if (job.result) return this.renderDone(job, job.result);
        this.renderMessage('Estimate finished but produced no result.');
    }

    private renderQueued(): void {
        const section = this.reset();
        const p = document.createElement('p');
        p.className = 'screen-loading';
        p.textContent = 'Estimating your meal… you can leave this screen — we’ll notify you when it’s ready.';
        section.appendChild(p);
    }

    private renderFailed(job: EstimateJob): void {
        const section = this.reset();
        const error = job.error ?? 'Unknown error';
        // Story 241: GPU contention is deferrable, not a broken estimate — the
        // drain stores a `gpu_contended:` prefix. Give the (admin) user the
        // context to act: retry, or pause Immich's indexing first.
        const contended = error.startsWith(`${GPU_CONTENDED_REASON}:`);
        if (contended) {
            const hint = document.createElement('p');
            hint.className = 'estimate-review-hint';
            hint.textContent = 'The GPU was busy with Immich photo indexing, so the estimate was held off rather than risk a crash. Retry now — or pause Immich’s jobs first if it’s still indexing.';
            section.appendChild(hint);
        }
        const pre = document.createElement('pre');
        pre.className = 'screen-error';
        pre.textContent = `Estimate ${contended ? 'delayed — GPU busy' : 'failed'}:\n${error}`;
        section.appendChild(pre);
        section.appendChild(this.actions([
            { label: 'Retry', primary: true, onClick: () => this.retry() },
            { label: 'Discard', onClick: () => this.archive(job) },
        ]));
    }

    private renderDone(job: EstimateJob, result: EstimateJobResult): void {
        const section = this.reset();

        if (job.image_path) {
            const img = document.createElement('img');
            img.className = 'estimate-review-image';
            img.src = FilesService.variantUrl(job.image_path, 'display.jpg');
            img.alt = result.kind === 'meal' ? result.meal_name : result.food_item.display_name;
            section.appendChild(img);
        }

        const title = document.createElement('h2');
        title.textContent = result.kind === 'meal' ? result.meal_name : result.food_item.display_name;
        section.appendChild(title);

        if (result.kind === 'meal') {
            const list = document.createElement('ul');
            list.className = 'estimate-review-ingredients';
            for (const ing of result.ingredients) {
                const li = document.createElement('li');
                const name = document.createElement('span');
                name.className = 'ingredient-name';
                name.textContent = `${ing.food_item.display_name} — ${Math.round(ing.amount)}${ing.food_item.base_unit === 'piece' ? '×' : 'g'}`;
                const badge = document.createElement('span');
                badge.className = `provenance-badge ${PROVENANCE_CLASS[ing.provenance]}`;
                badge.textContent = PROVENANCE_LABELS[ing.provenance];
                li.append(name, badge);
                list.appendChild(li);
            }
            section.appendChild(list);
        } else {
            const badge = document.createElement('span');
            badge.className = `provenance-badge ${PROVENANCE_CLASS[result.resolution.provenance]}`;
            badge.textContent = PROVENANCE_LABELS[result.resolution.provenance];
            section.appendChild(badge);
        }

        const total = document.createElement('p');
        total.className = 'estimate-review-total';
        total.textContent = `~${Math.round(resultKcal(result))} kcal · for ${job.meal_type} on ${job.date}`;
        section.appendChild(total);

        const buttons: Array<{ label: string; primary?: boolean; onClick: () => void }> = [
            { label: 'Log it', primary: true, onClick: () => this.accept(job) },
        ];
        if (result.kind === 'meal') {
            buttons.push({ label: 'Edit ingredients', onClick: () => this.editAsDraft(job, result) });
        }
        buttons.push({ label: 'Discard', onClick: () => this.archive(job) });
        section.appendChild(this.actions(buttons));
    }

    private actions(buttons: Array<{ label: string; primary?: boolean; onClick: () => void }>): HTMLElement {
        const row = document.createElement('div');
        row.className = 'estimate-review-actions';
        for (const b of buttons) {
            const btn = document.createElement('button');
            btn.type = 'button';
            btn.className = b.primary ? 'btn-primary' : 'btn-secondary';
            btn.textContent = b.label;
            btn.addEventListener('click', b.onClick);
            row.appendChild(btn);
        }
        return row;
    }

    /** Log it — materialize + log the meal/food server-side, then show the day. */
    private accept(job: EstimateJob): void {
        void safeExec(this, this.log, async () => {
            await HealthService.acceptEstimateJob(job.id, { log: true });
            // The meal + log entries were created server-side (estimate endpoints
            // are server-only). Pull them into the local OPFS replica before
            // navigating, or the day screen reads a stale snapshot (story 211).
            await refreshIfStale();
            navigate(`/health/day/${encodeURIComponent(job.date)}`);
        });
    }

    /**
     * Edit ingredients — no meal is created. Mark the job reviewed (the user is
     * taking over manually), pull the server-created ingredient rows into the
     * local replica, then open a meal DRAFT seeded with the estimate's
     * ingredients + amounts; the meal is created only when they Save.
     */
    private editAsDraft(job: EstimateJob, result: EstimateJobResult): void {
        if (result.kind !== 'meal') return;
        void safeExec(this, this.log, async () => {
            await HealthService.archiveEstimateJob(job.id);
            await refreshIfStale();
            const params = new URLSearchParams({
                fromIngredients: result.ingredients.map((ing) => `${ing.food_item_id}:${ing.amount}`).join(','),
                draftName: result.meal_name,
                // Carry the day/meal slot so saving the edited draft also LOGS it
                // there — the estimate was started to log a meal, not just bank a
                // template. The meals screen logs + returns to the day on save.
                logDate: job.date,
                logMeal: job.meal_type,
            });
            if (job.image_path) params.set('draftImage', job.image_path);
            navigate(`/health/meals?${params.toString()}`);
        });
    }

    private archive(job: EstimateJob): void {
        void safeExec(this, this.log, async () => {
            await HealthService.archiveEstimateJob(job.id);
            navigate(`/health/day/${encodeURIComponent(job.date)}`);
        });
    }

    private retry(): void {
        if (!this.jobIdValue) return;
        void safeExec(this, this.log, async () => {
            await HealthService.retryEstimateJob(this.jobIdValue!);
            await this.load();
        });
    }
}

if (!customElements.get('health-estimate-review-screen')) {
    customElements.define('health-estimate-review-screen', HealthEstimateReviewScreen);
}
